member.example:
Bind the TMP_Dropdown options list using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownOptionsBinder _options;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public List<string> _options;
    }


Bind the TMP_Dropdown options list by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TMP_Dropdown _dropdown;
        
        private DropdownOptionsBinder Options =>
            new(_dropdown);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public List<string> _options;
    }

Switch the TMP_Dropdown options list between two values using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownOptionsSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the TMP_Dropdown options list between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TMP_Dropdown _dropdown;
        
        [SerializeField] 
        private List<TMP_Dropdown.OptionData> _expandedOptions;
        
        [SerializeField] 
        private List<TMP_Dropdown.OptionData> _collapsedOptions;
        
        private DropdownOptionsSwitcherBinder IsExpanded => new(
            _dropdown, _expandedOptions, _collapsedOptions);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
